import{_ as i,o as a,c as s,ak as r}from"./chunks/framework.DiS-pR0X.js";const b=JSON.parse('{"title":"3. Cálculo de Dirección MAC a partir de IPv6","description":"","frontmatter":{"title":"3. Cálculo de Dirección MAC a partir de IPv6","parent":"IPv6"},"headers":[],"relativePath":"redes/ipv6/ipv6_to_mac.md","filePath":"redes/ipv6/ipv6_to_mac.md","lastUpdated":1775408517000}'),o={name:"redes/ipv6/ipv6_to_mac.md"};function t(l,e,d,n,c,p){return a(),s("div",null,[...e[0]||(e[0]=[r('<h1 id="🔄-proceso-inverso-ipv6-eui-64-→-mac-address" tabindex="-1">🔄 Proceso Inverso: IPv6 (EUI-64) → MAC Address <a class="header-anchor" href="#🔄-proceso-inverso-ipv6-eui-64-→-mac-address" aria-label="Permalink to “🔄 Proceso Inverso: IPv6 (EUI-64) → MAC Address”">​</a></h1><p>A partir de una <strong>dirección IPv6 link-local</strong> generada con <strong>SLAAC + EUI-64</strong>, podemos obtener la <strong>dirección MAC original</strong> siguiendo estos pasos:</p><hr><h2 id="ejemplo-direccion-ipv6-dada" tabindex="-1">Ejemplo: Dirección IPv6 dada <a class="header-anchor" href="#ejemplo-direccion-ipv6-dada" aria-label="Permalink to “Ejemplo: Dirección IPv6 dada”">​</a></h2><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>fe80::e67c:f9ff:fedb:b014</span></span></code></pre></div><hr><h2 id="paso-1-extraer-el-identificador-eui-64-ultimos-64-bits" tabindex="-1">Paso 1: Extraer el identificador EUI-64 (últimos 64 bits) <a class="header-anchor" href="#paso-1-extraer-el-identificador-eui-64-ultimos-64-bits" aria-label="Permalink to “Paso 1: Extraer el identificador EUI-64 (últimos 64 bits)”">​</a></h2><p>De la dirección completa, tomamos la parte después de <code>fe80::</code>:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>e67c:f9ff:fedb:b014</span></span></code></pre></div><p>Convertimos los hextetos a bytes individuales:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>e6 7c f9 ff fe db b0 14</span></span></code></pre></div><hr><h2 id="paso-2-eliminar-los-bytes-ff-fe-insertados" tabindex="-1">Paso 2: Eliminar los bytes <code>ff:fe</code> insertados <a class="header-anchor" href="#paso-2-eliminar-los-bytes-ff-fe-insertados" aria-label="Permalink to “Paso 2: Eliminar los bytes ff:fe insertados”">​</a></h2><p>Quitamos los bytes del medio (<code>ff</code> y <code>fe</code>), que fueron añadidos para formar el EUI-64:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>e6 7c f9 db b0 14</span></span></code></pre></div><hr><h2 id="paso-3-invertir-el-bit-u-l-del-primer-byte" tabindex="-1">Paso 3: Invertir el bit U/L del primer byte <a class="header-anchor" href="#paso-3-invertir-el-bit-u-l-del-primer-byte" aria-label="Permalink to “Paso 3: Invertir el bit U/L del primer byte”">​</a></h2><p>El primer byte es <code>e6</code> → binario: <code>11100110</code></p><p>Invertimos el <strong>7.º bit (U/L bit)</strong>:</p><ul><li><code>11100110</code> → <code>11100100</code> → hexadecimal: <code>e4</code></li></ul><hr><h2 id="paso-4-reconstruir-la-direccion-mac" tabindex="-1">Paso 4: Reconstruir la dirección MAC <a class="header-anchor" href="#paso-4-reconstruir-la-direccion-mac" aria-label="Permalink to “Paso 4: Reconstruir la dirección MAC”">​</a></h2><p>Juntamos los bytes finales:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>e4:7c:f9:db:b0:14</span></span></code></pre></div><p>¡Y coincide con la dirección MAC original!</p><hr><h2 id="resumen-del-proceso-inverso" tabindex="-1">Resumen del proceso inverso <a class="header-anchor" href="#resumen-del-proceso-inverso" aria-label="Permalink to “Resumen del proceso inverso”">​</a></h2><ol><li>Quitar <code>fe80::/64</code> del inicio.</li><li>Tomar los últimos 64 bits (Interface Identifier).</li><li>Quitar los bytes <code>ff:fe</code> insertados.</li><li>Invertir el bit U/L del primer byte.</li><li>Convertir los bytes resultantes a formato MAC.</li></ol>',28)])])}const f=i(o,[["render",t]]);export{b as __pageData,f as default};
